package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP01PanelCocineroTest extends BaseTest {    @Test    void panelCocineroMuestraPedidosPendientes() {        try {            System.out.println("Panel Cocinero muestra pedidos pendientes al ingresar");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            Thread.sleep(3000);            CocineroPage cocineroPage = new CocineroPage(driver);            Assertions.assertTrue(                    cocineroPage.panelVisible(),                    "El Panel Cocinero no se muestra después del inicio de sesión."            );            Assertions.assertTrue(                    cocineroPage.pedidosPendientesVisible(),                    "La sección Pedidos Pendientes no se muestra en el panel."            );            System.out.println("HP-01 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail(                    "Error durante la ejecución del caso de prueba HP-01: "                            + e.getMessage()            );        }    }}